const parsed = $('Parsear Mensaje WA').first().json;
const msg = (parsed.textContent || '').toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// Categorías de producto
const catMap = {
  anillos:   /\banill[oa]s?\b/,
  collares:  /\bcollar(es)?\b/,
  aretes:    /\barete[s]?\b|\bzarcillo[s]?\b|\bpendiente[s]?\b/,
  pulseras:  /\bpulsera[s]?\b|\bbrazalete[s]?\b/,
  piercings: /\bpiercing[s]?\b/,
};
const detectedCats = Object.entries(catMap)
  .filter(([, rx]) => rx.test(msg))
  .map(([cat]) => cat);

// ID de producto específico: an-01, co-03, ar-02, etc.
const productMatch = msg.match(/\b(an|co|ar|pu|pi)-?0?\d{1,2}\b/i);
const productId = productMatch
  ? productMatch[0].replace(/^(an|co|ar|pu|pi)(\d)/i, '$1-$2').toLowerCase()
  : null;

// El cliente quiere explorar / ver el catálogo -> le damos el LINK del sitio (0 tokens de productos)
const wantsCatalog = /catalogo|ver todo|todos los productos|que (tienen|tienes|manejan|venden|ofrecen|joyas|hay)|que mas|muestrame|ensename|recomi|opciones/.test(msg);

// MÁXIMO AHORRO: solo se inyecta catálogo real en category/product.
// full_catalog -> link.  Todo lo demás (FAQ, checkout, charla) -> none (0 tokens).
let catalogMode;
if (wantsCatalog)                  catalogMode = 'full_catalog';
else if (productId)                catalogMode = 'product';
else if (detectedCats.length > 0)  catalogMode = 'category';
else                               catalogMode = 'none';

return [{ json: { catalogMode, catFilter: detectedCats[0] || null, productId } }];

const data = $('Parsear Mensaje WA').first().json;
const quoteCode = (data.quoteCode || '').trim();
if (!quoteCode) return [];
return [{ json: { quoteCode, phone: data.from } }];

let row = null;
try { const rows = $('Buscar Datos Cotización').first().json.body || []; row = rows[0] || null; } catch (e) {}
return [{ json: {
  quote_code: row ? row.code : null,
  subtotal: row ? row.subtotal : null,
  discount_code: row ? row.discount_code : null,
  discount_amount: row ? row.discount_amount : null,
  total: row ? row.total : null,
} }];

const item = $input.first().json;
const bin  = $input.first().binary;
const crypto = require('crypto');

let secret = '';
try { secret = $env.APP_SECRET || ''; } catch (e) {}
let enforce = false;
try { enforce = String($env.WA_SIG_ENFORCE || '').toLowerCase() === 'true'; } catch (e) {}

// Cuerpo crudo exacto que firmó Meta (binary 'data' o item.rawBody)
let raw = '';
if (bin && bin.data && bin.data.data) {
  raw = Buffer.from(bin.data.data, 'base64').toString('utf8');
} else if (typeof item.rawBody === 'string') {
  raw = item.rawBody;
}

let body = item.body;
if (raw) { try { body = JSON.parse(raw); } catch (e) {} }

const headers   = item.headers || {};
const sigHeader = headers['x-hub-signature-256'] || headers['X-Hub-Signature-256'] || '';

let sigValid = false;
if (secret && raw && sigHeader.indexOf('sha256=') === 0) {
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(raw, 'utf8').digest('hex');
  try {
    const a = Buffer.from(expected);
    const b = Buffer.from(sigHeader);
    sigValid = a.length === b.length && crypto.timingSafeEqual(a, b);
  } catch (e) { sigValid = false; }
}

if (sigValid) {
  console.log('[VETA][B1] Firma válida ✓');
} else {
